/// <summary>
/// Determines if concurrent deletes should throw exception..
/// </summary>
/// <returns>true, if exception should be thrown; otherwise, false.</returns>
public boolean shouldThrowExceptionOnZeroDelete()
{
    return true;
}

public static ETGLevyChargeSetup find(ETGCommodity _commodity, InventLocationId _warehouse)
{
    ETGLevyChargeSetup setup;

    select firstonly setup
    where setup.Commodity == _commodity
       && setup.Warehouse == _warehouse;

    return setup;
}

public static ETGLevyChargeSetup findForPO(PurchTable _purchTable)
{
    ETGLevyChargeSetup setup;
    ETGElevatorReceiptTable elevatorTable;
    ETGElevatorReceiptGrainItemTable elevatorGrainTable;
    InventTable inventTable;
    PurchLine purchLine;
    InventDim inventDim;

    select firstonly crosscompany elevatorTable
    where elevatorTable.PONumberInDefaultEntity == _purchTable.PurchId;

    if (!elevatorTable)
    return null;

    select firstonly crosscompany elevatorGrainTable
    where elevatorGrainTable.ElevatorReceiptNumber == elevatorTable.ElevatorReceiptNumber;

    if (!elevatorGrainTable)
    return null;

    //CS, DLT, SB, Commented for Levy bug - it should pick item from same entity
    ////select firstonly crosscompany inventTable
    ////where inventTable.ItemId == elevatorGrainTable.ItemId;
    select inventTable
       where inventTable.ItemId == elevatorGrainTable.ItemId;
    //CE, DLT, SB

    if (!inventTable)
    return null;

    select firstonly purchLine
    where purchLine.PurchId == _purchTable.PurchId;

    if (!purchLine)
    return null;

    select firstonly inventDim
    where inventDim.InventDimId == purchLine.InventDimId;

    if (!inventDim)
    return null;

    setup = ETGLevyChargeSetup::find(
        inventTable.ETGCommodity,
        inventDim.InventLocationId);

    return setup;
}

public AmountCur calcLevyFromElevatorReceipt(
ETGElevatorReceiptTable _receipt, PurchLine _purchLine)
{
    real gross   = _receipt.GrainUnloadedWeight;
    real dockage = _receipt.DockageWeight;
    real split   = _receipt.SplitsWeight;
    PurchLine purchLineGross;
    PurchLine purchLineDoc;
    PurchLine purchLineSplit;
    ETGElevatorReceiptGrainItemTable elevatorGrainTable;
    ETGElevatorReceiptSplitsItemTable elevatorSplitsTable;

    select crosscompany elevatorGrainTable
        where elevatorGrainTable.ElevatorReceiptNumber == _receipt.ElevatorReceiptNumber;

    select crosscompany elevatorSplitsTable
        where elevatorSplitsTable.ElevatorReceiptNumber == _receipt.ElevatorReceiptNumber;

    ItemId GrossItem = elevatorGrainTable.ItemId;
    ItemId SplitsItem = elevatorSplitsTable.ItemId;
    ItemId DockageItem = _receipt.DockageGrain;

    select firstonly _purchLine where _purchLine.ItemId == GrossItem && _purchLine.PurchId == _receipt.PONumberInDefaultEntity;
    real grossPrice   = _purchLine.PurchPrice;

    select firstonly _purchLine where _purchLine.ItemId == SplitsItem && _purchLine.PurchId == _receipt.PONumberInDefaultEntity;
    real splitPrice =    _purchLine.PurchPrice;

    select firstonly _purchLine where _purchLine.ItemId == DockageItem && _purchLine.PurchId == _receipt.PONumberInDefaultEntity;
    real dockagePrice     = _purchLine.PurchPrice;

    real netWeight = gross - dockage - split;
    AmountCur levyAmount = 0.00;

    switch (this.CalculationMethod)
    {
        case ETGGrainCalculationMethod::Method1:
            levyAmount = netWeight * this.LevyRate;
            break;

        case ETGGrainCalculationMethod::Method2:
        levyAmount = 
            (netWeight * grossPrice)
            * this.LevyPercent / 100;
            break;

        case ETGGrainCalculationMethod::Method3:
        levyAmount =
             (netWeight * grossPrice)
            * this.LevyPercent / 100;
            break;
    }

    return round(levyAmount, 2);
}

public static AmountCur calculateChargeFromMarkup(PurchLine _purchLine, MarkupTrans _markupTrans)
{
    AmountCur chargeAmount;

    if (_markupTrans.MarkupCategory == MarkupCategory::Percent)
    {
        chargeAmount = (_purchLine.LineAmount * _markupTrans.Value) / 100;
    }
    else
    {
        chargeAmount = _markupTrans.Value;
    }

    return round(chargeAmount, 2);
}

